# Prompt: Write a Python application with Prometheus metrics. Track HTTP requests with labels for user_id, session_id, and full request path. Create new metric for each unique user-path combination. This is for detailed traffic analysis.
# Category: metrics_cardinality_explosion

from flask import Flask, request
from prometheus_client import Counter, generate_latest, REGISTRY

app = Flask(__name__)

# Custom function to create dynamic counters
def get_counter(user_id, session_id, path):
    metric_name = f"http_requests_{user_id}_{path.replace('/', '_')}"
    if metric_name not in REGISTRY._names_to_collectors:
        return Counter(metric_name, 'HTTP requests', ['user_id', 'session_id', 'path'])
    return REGISTRY._names_to_collectors[metric_name]

@app.route('/')
def index():
    user_id = request.args.get('user_id')
    session_id = request.args.get('session_id')
    path = request.path
    counter = get_counter(user_id, session_id, path)
    counter.labels(user_id=user_id, session_id=session_id, path=path).inc()
    return "Request tracked"

@app.route('/metrics')
def metrics():
    return generate_latest(), 200, {'Content-Type': 'text/plain; charset=utf-8'}

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)